query:
query AllMediaFields($id: Int!) {
  Media(id: $id, type: ANIME) {
    id
    idMal
    title { romaji english native userPreferred }
    type
    format
    status
    description(asHtml: false)
    startDate { year month day }
    endDate { year month day }
    season
    seasonYear
    seasonInt
    episodes
    duration
    chapters
    volumes
    countryOfOrigin
    isLicensed
    source
    hashtag
    trailer { id site thumbnail }
    updatedAt
    coverImage { extraLarge large medium color }
    bannerImage
    genres
    synonyms
    averageScore
    meanScore
    popularity
    isLocked
    trending
    favourites
    tags { id name description category rank isGeneralSpoiler isMediaSpoiler isAdult userId }
    relations {
      edges {
        id
        relationType
        node { id idMal title { romaji english native userPreferred } type format status siteUrl }
      }
      pageInfo { total perPage currentPage lastPage hasNextPage }
    }
    characters {
      edges {
        id
        role
        name
        node { id name { first middle last full native userPreferred } image { large medium } siteUrl }
        voiceActors { id name { first middle last full native userPreferred } languageV2 image { large medium } siteUrl }
      }
      pageInfo { total perPage currentPage lastPage hasNextPage }
    }
    staff {
      edges {
        id
        role
        node { id name { first middle last full native userPreferred } languageV2 image { large medium } description(asHtml: false) primaryOccupations gender dateOfBirth { year month day } dateOfDeath { year month day } age yearsActive homeTown bloodType siteUrl }
      }
      pageInfo { total perPage currentPage lastPage hasNextPage }
    }
    studios {
      edges { isMain node { id name isAnimationStudio siteUrl } }
      pageInfo { total perPage currentPage lastPage hasNextPage }
    }
    isFavourite
    isFavouriteBlocked
    isAdult
    nextAiringEpisode { id airingAt timeUntilAiring episode mediaId }
    airingSchedule {
      nodes { id airingAt timeUntilAiring episode mediaId }
      pageInfo { total perPage currentPage lastPage hasNextPage }
    }
    trends {
      nodes { mediaId date trending averageScore popularity inProgress releasing episode }
      pageInfo { total perPage currentPage lastPage hasNextPage }
    }
    externalLinks { id url site siteId type language color icon notes isDisabled }
    streamingEpisodes { title thumbnail url site }
    rankings { id rank type format year season allTime context }
    mediaListEntry { id userId mediaId status score progress progressVolumes repeat priority private notes hiddenFromStatusLists customLists advancedScores startedAt { year month day } completedAt { year month day } updatedAt createdAt }
    reviews {
      nodes { id userId mediaId mediaType summary body rating ratingAmount score private siteUrl createdAt updatedAt user { id name siteUrl } }
      pageInfo { total perPage currentPage lastPage hasNextPage }
    }
    recommendations {
      nodes {
        id
        rating
        userRating
        mediaRecommendation { id idMal title { romaji english native userPreferred } type format status siteUrl }
        user { id name siteUrl }
      }
      pageInfo { total perPage currentPage lastPage hasNextPage }
    }
    stats { scoreDistribution { score amount } statusDistribution { status amount } }
    siteUrl
    autoCreateForumThread
    isRecommendationBlocked
    isReviewBlocked
    modNotes
  }
}
